 29→/** Accepts peripheral input, mapping via various keybinding strategies,
 30→ * and converting them to commands for the Reviewer.  */
 31→class PeripheralKeymap(reviewerUi: ReviewerUi, commandProcessor: ViewerCommand.CommandProcessor) {
 32→    private val keyMap: KeyMap
 33→    private var hasSetup = false
 34→    fun setup() {
 35→        val preferences = AnkiDroidApp.instance.sharedPrefs()
 36→        setup(preferences)
 37→    }
 38→
 39→    fun setup(preferences: SharedPreferences) {
 40→        for (command in ViewerCommand.entries) {
 41→            add(command, preferences)
 42→        }
 43→        hasSetup = true
 44→    }
 45→
 46→    private fun add(command: ViewerCommand, preferences: SharedPreferences) {
 47→        val bindings = fromPreference(preferences, command)
 48→            .filter { it.screen is Screen.Reviewer }
 49→        for (b in bindings) {
 50→            if (!b.isKey) {
 51→                continue
 52→            }
 53→            keyMap[b] = command
 54→        }
 55→    }
 56→
 57→    fun onKeyDown(keyCode: Int, event: KeyEvent): Boolean {
 58→        return if (!hasSetup || event.repeatCount > 0) {
 59→            false
 60→        } else {
 61→            keyMap.onKeyDown(keyCode, event)
 62→        }
 63→    }
 64→
 65→    @Suppress("UNUSED_PARAMETER")
 66→    fun onKeyUp(keyCode: Int, event: KeyEvent?): Boolean {
 67→        return false
 68→    }
 69→
 70→    class KeyMap(
 71→        private val processor: ViewerCommand.CommandProcessor,
 72→        private val reviewerUI: ReviewerUi,
 73→        private val screenBuilder: (CardSide) -> Screen
 74→    ) {
 75→        val bindingMap = HashMap<MappableBinding, ViewerCommand>()
 76→
 77→        @Suppress("UNUSED_PARAMETER")
 78→        fun onKeyDown(keyCode: Int, event: KeyEvent?): Boolean {
 79→            var ret = false
 80→            val bindings = possibleKeyBindings(event!!)
 81→            val side = fromAnswer(reviewerUI.isDisplayingAnswer)
 82→            for (b in bindings) {
 83→                val binding = MappableBinding(b, screenBuilder(side))
 84→                val command = bindingMap[binding] ?: continue
 85→                ret = ret or processor.executeCommand(command, fromGesture = null)
 86→            }
 87→            return ret
 88→        }
 89→
 90→        operator fun set(key: MappableBinding, value: ViewerCommand) {
 91→            bindingMap[key] = value
 92→        }
 93→
 94→        operator fun get(key: MappableBinding): ViewerCommand? {
 95→            return bindingMap[key]
 96→        }
 97→    }
 98→
 99→    init {
100→        keyMap = KeyMap(commandProcessor, reviewerUi) { Screen.Reviewer(it) }
101→    }
