 29→/** Accepts peripheral input, mapping via various keybinding strategies,
 30→ * and converting them to commands for the Reviewer.  */
 31→class PeripheralKeymap(reviewerUi: ReviewerUi, commandProcessor: ViewerCommand.CommandProcessor) {
 32→    private val keyMap: KeyMap
 33→    private var hasSetup = false
 34→    fun setup() {
 35→        val preferences = AnkiDroidApp.instance.sharedPrefs()
 36→        setup(preferences)
 37→    }
 38→
 39→    fun setup(preferences: SharedPreferences) {
 40→        for (command in ViewerCommand.entries) {
 41→            add(command, preferences)
 42→        }
 43→        hasSetup = true
 44→    }
 45→
 46→    private fun add(command: ViewerCommand, preferences: SharedPreferences) {
 47→        val bindings = fromPreference(preferences, command)
 48→            .filter { it.screen is Screen.Reviewer }
 49→        for (b in bindings) {
 50→            if (!b.isKey) {
 51→                continue
 52→            }
 53→            keyMap[b] = command
 54→        }
 55→    }
 56→
 57→    fun onKeyDown(keyCode: Int, event: KeyEvent): Boolean {
 58→        return if (!hasSetup || event.repeatCount > 0) {
 59→            false
 60→        } else {
 61→            keyMap.onKeyDown(keyCode, event)
 62→        }
 63→    }
 64→
 65→    @Suppress("UNUSED_PARAMETER")
 66→    fun onKeyUp(keyCode: Int, event: KeyEvent?): Boolean {
 67→        return false
 68→    }
