// User Actions (compatible with AnkiMobile's userJs1-8 feature)
function _ankiRunUserAction(action) {
    if (action == null) {
        return;
    }

    try {
        if (typeof action === "function") {
            action();
            return;
        }

        // Support a string of JavaScript code.
        if (typeof action === "string") {
            if (action.trim().length === 0) {
                return;
            }
            // Indirect eval runs in global scope.
            (0, eval)(action);
        }
    } catch (e) {
        console.log(e);
    }
}

function ankiUserAction(n) {
